import { AutkSpatialDb } from 'autk-db';

const db = new AutkSpatialDb();
await db.init();

await db.loadOsm({
    queryArea: { geocodeArea: 'Chicago', areas: ['Loop'] },
    outputTableName: 'table_osm',
    autoLoadLayers: {
        coordinateFormat: 'EPSG:3395',
        layers: ['buildings'],
        dropOsmTable: true,
    },
});

const layers = [];
for (const layer of db.getLayerTables()) {
    layers.push({ name: layer.name, type: layer.type, geojson: await db.getLayer(layer.name) });
}
return layers;

// Annotate every building feature with footprint area (m²) and parsed
// height (m). EPSG:3395 coords are global Mercator (~1e7 magnitude), so
// shoelace is run against a per-polygon local origin to preserve
// precision for small footprints. OSM 'height' tags are strings
// (e.g. '30', '120 ft') so we extract the leading number.
const ringArea = (ring) => {
    if (!ring || ring.length < 3) return 0;
    const ox = ring[0][0], oy = ring[0][1];
    let s = 0;
    for (let i = 0; i < ring.length; i++) {
        const j = (i + 1) % ring.length;
        const x1 = ring[i][0] - ox, y1 = ring[i][1] - oy;
        const x2 = ring[j][0] - ox, y2 = ring[j][1] - oy;
        s += x1 * y2 - x2 * y1;
    }
    return Math.abs(s) / 2;
};
const featureArea = (geom) => {
    if (!geom) return null;
    if (geom.type === 'Polygon') return ringArea(geom.coordinates[0]);
    if (geom.type === 'MultiPolygon') return geom.coordinates.reduce((s, p) => s + ringArea(p[0]), 0);
    // autk-db emits one Feature per building with a GeometryCollection of the
    // building's parts; sum each part's outer-ring area.
    if (geom.type === 'GeometryCollection') return (geom.geometries || []).reduce((s, g) => s + (featureArea(g) || 0), 0);
    return null;
};
const parseHeight = (h) => {
    if (h == null) return null;
    if (typeof h === 'number') return Number.isFinite(h) ? h : null;
    const m = String(h).match(/-?\d+(?:\.\d+)?/);
    return m ? parseFloat(m[0]) : null;
};

return arg.map(layer => {
    if (layer.name !== 'table_osm_buildings') return layer;
    const features = layer.geojson.features.map(f => ({
        ...f,
        properties: {
            ...f.properties,
            area: featureArea(f.geometry),
            height: parseHeight(f.properties?.height),
        },
    }));
    return { ...layer, geojson: { ...layer.geojson, features } };
});

// Render buildings, color by height, and enable picking.
const map = new AutkMap(container);
await map.init();
for (const layer of arg) {
    map.loadCollection(layer.name, { collection: layer.geojson, type: layer.type });
}
const buildings = arg.find(l => l.name === 'table_osm_buildings').geojson;
map.updateRenderInfo('table_osm_buildings', { isPick: true, isColorMap: true });
map.updateThematic('table_osm_buildings', { collection: buildings, property: 'properties.height' });
map.draw();
return map;

// Scatter footprint area (m²) vs height (m). Both attributes come
// from the upstream Compute node. Buildings missing a height tag fall
// off the y axis as NaN.
const buildings = arg.find(l => l.name === 'table_osm_buildings').geojson;
return new AutkChart(container, {
    type: 'scatterplot',
    collection: buildings,
    attributes: { axis: ['area', 'height'] },
    labels: { axis: ['Footprint area (m²)', 'Height (m)'], title: 'Chicago Loop buildings' },
    width: 600,
    height: 380,
    events: ['brush'],
});
